const data = JSON.parse($input.item.json.stdout || '[]');
const pending = data.filter(m => !m.sent_at);

if (pending.length === 0) return [];

// Group by priority
// 0 = Critical (immediate batch logic - or maybe we just send daily digest for all > 0)
const highPriority = pending.filter(m => m.priority <= 1);
const normalPriority = pending.filter(m => m.priority > 1);

// For now, let's just batch EVERYTHING into a digest if it's the scheduled time (6am or 9:30pm)
// OR if there are critical messages, send them now.

const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();

const isDigestTime = (hour === 6 && minute < 15) || (hour === 21 && minute > 25 && minute < 45);

if (!isDigestTime && highPriority.length === 0) {
  return []; // Nothing to send right now
}

return [{
  json: {
    messages: pending,
    ids: pending.map(m => m.id)
  }
}];

const messages = $input.item.json.messages;
const digest = messages.map(m => {
  const emoji = m.priority === 0 ? '🚨' : (m.priority === 1 ? '⚠️' : 'ℹ️');
  return `${emoji} *[${m.pa_name}]* ${m.message}`;
}).join('\n\n');

return [{
  json: {
    text: `🔔 *NYX Digest*\n\n${digest}`
  }
}];

const ids = $node["Batch Logic"].json.ids;
return [{
  json: {
    command: `node -e 'const fs = require("fs"); const f = "/pantheon-data/nyx_queue.json"; const d = JSON.parse(fs.readFileSync(f)); const ids = ${JSON.stringify(ids)}; const updated = d.map(m => ids.includes(m.id) ? {...m, sent_at: new Date().toISOString()} : m); fs.writeFileSync(f, JSON.stringify(updated, null, 2));'`
  }
}];
